# -*- coding: utf-8 -*-"""Script mínimo para verificar que PyTorch (compilado con ROCm)detecta y usa tu GPU AMD en Windows."""import torchprint("="*60)print("Prueba PyTorch + ROCm (GPU AMD)")print("="*60)print("Versión de PyTorch:", torch.__version__)print("torch.cuda.is_available():", torch.cuda.is_available())print("torch.version.hip:", getattr(torch.version, "hip", None))if torch.cuda.is_available():    device = torch.device("cuda")  # En ROCm se expone como 'cuda'    print("ID de dispositivo actual:", torch.cuda.current_device())    print("Nombre del dispositivo:", torch.cuda.get_device_name(0))    # Operación de prueba en GPU    x = torch.randn(1000, 1000, device=device)    y = torch.randn(1000, 1000, device=device)    z = torch.matmul(x, y)    print("Operación matricial realizada en:", z.device)else:    print("No se detectó GPU compatible con ROCm/CUDA. Usando CPU.")print("="*60)